// SECCION 2
//CRITERIOS DE LIQUIDACION
var arrLIQUIDACIONES;

//Ejecuta el Query Seleccionado y devuelve un ARRAY con el resultado
function exec_liq_qry()
{

	if (Ctrl('oi_personal_emp').GetXValue()=='' || Ctrl('oi_personal_emp').GetXValue()==undefined)
		{
			alert("Debe seleccionar un legajo.");
			Ctrl('oi_personal_emp').SetFocus();
			return null;
		}		

	var np, nSQL;
	np = GetProxy();
	nSQL = np.SQLService(); 	

	var qry = Ctrl("main").getResource("LIQ_qry_liquidacion"); 

	var nmdDATA=new NomadXML("PARAM");
	// particulares
	nmdDATA.SetAttr("oi_personal_emp", Ctrl('oi_personal_emp').GetXValue());
	nmdDATA.SetAttr("oi_empresa", Ctrl('oi_empresa').GetXValue()); 
  // de liquidación 
  nmdDATA.SetAttr("liq_f_liq_des", Ctrl('liq_f_liq_des').GetXValue()); 
  nmdDATA.SetAttr("liq_f_liq_has", Ctrl('liq_f_liq_has').GetXValue());

  nmdDATA.SetAttr("liq_f_pag_des", Ctrl('liq_f_pag_des').GetXValue()); 
  nmdDATA.SetAttr("liq_f_pag_has", Ctrl('liq_f_pag_has').GetXValue());  


	var result = nSQL.GetXML(qry, nmdDATA.ToString());
  var resultArray = XML2array(result);

  return resultArray;

}

function ONLOAD()
{
	var t, ROW, VALUES;
	arrLIQUIDACIONES = new Array();

	//Valores Iniciales
	for (t=0; t<Ctrl("LIQ_arrFILTER").CountRow(); t++)
	{
		ROW=Ctrl("LIQ_arrFILTER").GetRow(t);
		VALUES=ROW.GetAttr("VALUES").split(",");
		for (d=0; d<VALUES.length; d++)
			if (VALUES[d]!="")
				arrLIQUIDACIONES.push(VALUES[d]);
	} 

 	//limpio la Lista de LIQ
	clearLIQ();       
} 

function checkDevengado()
{ 
	if(Ctrl('l_devengado').GetXValue()=='1')
		{
		Ctrl("l_percibido").SetXValue('0'); 
		Ctrl("liq_f_pag_des").SetXValue('');
		Ctrl("liq_f_pag_has").SetXValue(''); 
		CtrlEnabled("LIQ_PAGO" , false); 

		CtrlEnabled("LIQ_PERIODOS" , true);
		} 
  else 
  {
    Ctrl("l_devengado").SetXValue('1');
    Ctrl("l_percibido").SetXValue('0'); 
		Ctrl("liq_f_pag_des").SetXValue('');
		Ctrl("liq_f_pag_has").SetXValue(''); 
		CtrlEnabled("LIQ_PAGO" , false); 

		CtrlEnabled("LIQ_PERIODOS" , true); 
  }
}

function checkPercibido()
{  
   if(Ctrl('l_percibido').GetXValue()=='1')
		{
		Ctrl("l_devengado").SetXValue('0');
		Ctrl("liq_f_liq_des").SetXValue('');
		Ctrl("liq_f_liq_has").SetXValue(''); 

		CtrlEnabled("LIQ_PAGO" , true); 

		CtrlEnabled("LIQ_PERIODOS" , false); 
		}
	 else 
  {
    Ctrl("l_percibido").SetXValue('1'); 
  }	

}

function refreshLiquidacion()
{              
 	var page=Ctrl("LIQ_listFILTER").Page;
	Ctrl("LIQ_listFILTER").IDs=arrLIQUIDACIONES;
	Ctrl("LIQ_listFILTER").ResetSQL();
	Ctrl("LIQ_listFILTER").GotoPage(page);

	Ctrl("liq_filtrados").SetXValue("Liquidaciones Filtradas: "+arrLIQUIDACIONES.length);
	enable_buttons();
}

function liq_load()    { NomadTimeout("internal_liq_load();",100,"Cargando la Lista..."); }
function liq_filter()  { NomadTimeout("internal_liq_filter();",100,"Filtrando la Lista..."); }
function liq_loadadd() { NomadTimeout("internal_liq_loadadd();",100,"Agregando en la Lista..."); }        


function internal_liq_load()
{  
  var auxArr;
	auxArr = exec_liq_qry();
	if (auxArr==null) return;  

	arrLIQUIDACIONES=auxArr;	
	refreshLiquidacion();
}

function internal_liq_filter()
{
  var auxArr;
	auxArr = exec_liq_qry();
	if (auxArr==null) return;  

	intersect(arrLIQUIDACIONES, auxArr);	
	refreshLiquidacion();
}

function internal_liq_loadadd()
{
  var auxArr;
	auxArr = exec_liq_qry();
	if (auxArr==null) return;  

	union(arrLIQUIDACIONES, auxArr);	
	refreshLiquidacion();
}


//Elimino iten del FILTRO
function delLIQ()
{
	for (var X=0; X<arrLIQUIDACIONES.length; X++)
	{
		if (Ctrl("LIQ_arrcheckFILTER").GetRowByAttr("ID",arrLIQUIDACIONES[X])!=null)
		{                        
			arrLIQUIDACIONES.splice(X,1);
			X--;
		}
	}

	Ctrl("LIQ_listFILTER").SetXValue("");
 	Ctrl("LIQ_arrcheckFILTER").DelAllRow();
	refreshLiquidacion();
}

//Limpio la Lista del FILTRO
function clearLIQ()
{
	for (var X=0; X<arrLIQUIDACIONES.length; X++)
	{
		if (Ctrl("LIQ_arrcheckFILTER").GetRowByAttr("ID",arrLIQUIDACIONES[X])==null)
		{                        
			arrLIQUIDACIONES.splice(X,1);
			X--;
		}
	}

	Ctrl("LIQ_listFILTER").SetXValue("");
 	Ctrl("LIQ_arrcheckFILTER").DelAllRow();
	refreshLiquidacion(); 
	//pongo devengado por defecto
	checkDevengado(); 
}                 

//Deschequeo TOTAL
function unmarkLIQ()
{
	Ctrl("LIQ_listFILTER").SetXValue("");
 	Ctrl("LIQ_arrcheckFILTER").DelAllRow();
	refreshLiquidacion();
}


function checkLIQ()
{    
	var X=Ctrl("LIQ_listFILTER").GetXValue();
	if (X!="" && Ctrl("LIQ_listFILTER").LastColumnClick!="SEL")
	{                                                  
		if (Ctrl("LIQ_arrcheckFILTER").GetRowByAttr("ID",X)==null) Ctrl("LIQ_arrcheckFILTER").AddRow().SetAttr("ID",X);
		                                                      else Ctrl("LIQ_arrcheckFILTER").DelRowByAttr("ID",X);    

		Ctrl("LIQ_listFILTER").SetXValue("");
		refreshLiquidacion();
	} else           
		enable_buttons();
}


function enable_buttons()
{                       
	CtrlEnabled("LIQ_listFILTER_Delete", Ctrl("LIQ_arrcheckFILTER").CountRow()==0?false:true);
	CtrlEnabled("LIQ_listFILTER_Clear" , true);
}


function FillLiquidacionArray(numByRow)
{
	var t,n,values,sep,row,p;    
	var np, nSQL;

	np = GetProxy();
	nSQL = np.SQLService();


	//Genero el XML del IN
	Ctrl("LIQ_arrFILTER").DelAllRow(); 

	values=""; sep="";
	for (t=0,n=0,p=0; t<arrLIQUIDACIONES.length; t++, n++)
	{
		if (n>=numByRow)
		{              
			p++;
			row=Ctrl("LIQ_arrFILTER").AddRow()
			row.SetAttr("id", p);
			row.SetAttr("VALUES", values);
			values=""; sep=""; n=0;
		}                  

		values+=sep+arrLIQUIDACIONES[t];
		sep=",";
	}
	if (values!="") 
	{      
		p++;
		row=Ctrl("LIQ_arrFILTER").AddRow()
		row.SetAttr("id", p);
		row.SetAttr("VALUES", values);
	}

}

function Ejecutar()
{               


 	if (arrLIQUIDACIONES.length==0)
 	{             
 		alert("No hay liquidaciones filtradas.");
 		return false;
 	}

 	if (arrLIQUIDACIONES.length>100)
 	{             
 		alert("Demasiadas Liquidaciones.");
 		return false;
 	}

 	FillLiquidacionArray(100);
	Ctrl("main").DoEvent("ACCEPT");
}


//operaciones con arrays
//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{
  var t;
  var tmp=new Array();

  //Creo la HASH
  for (t=0; t<arrayA.length; t++) 
  tmp["K"+arrayA[t]]=1;

  //Agrego los que no estan
  for (t=0; t<arrayB.length; t++) 
    if (tmp["K"+arrayB[t]]?false:true)
      arrayA.push(arrayB[t]);
}


//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
  var t;
  var tmp1=new Array();
  var tmp2=new Array();

  //Creo la HASH
  for (t=0; t<arrayB.length; t++) 
    tmp1["K"+arrayB[t]]=1;
  for (t=0; t<arrayA.length; t++) 
    tmp2.push(arrayA[t]);

  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (t=0; t<tmp2.length; t++)      
    if (tmp1["K"+tmp2[t]]?false:true)
      arrayA.push(tmp2[t]);
} 

//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
  var t;
  var tmp1=new Array();
  var tmp2=new Array();   

  //Creo la HASH
  for (t=0; t<arrayB.length; t++) 
    tmp1["K"+arrayB[t]]=1;
  for (t=0; t<arrayA.length; t++) 
    tmp2.push(arrayA[t]);

  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (t=0; t<tmp2.length; t++)      
  if (tmp1["K"+tmp2[t]]?true:false)
    arrayA.push(tmp2[t]);
}

//Elimina del Array A los elementos que no estan en el Array B
function copiar(arrayA, arrayB)
{
  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (var t=0; t<arrayB.length; t++)      
    arrayA.push(arrayB[t]);
}

//Transaforma un XML(tipo STRING) en ARRAY
function XML2array(xml)
{
  var arr = new Array();
  for (var cur=xml.FirstChild(); cur!=null; cur=cur.Next())
  arr.push(cur.GetAttr("id"));
  return arr;
}

//Transaforma un XML(tipo STRING) en ARRAY
function STR2array(str)
{
  var arr = new Array();

  var cur = 0, pos;
  while(true) 
  {
    pos = str.indexOf("id=\"", cur);
    if (pos < 0) break;

    cur = pos+4;
    pos = str.indexOf("\"", cur);
    arr.push(str.substr(cur, pos-cur));
    cur = pos+1;
  }
  return arr;
}

qry:select.qry:xquery:
					for $r in sql('
SELECT 
LIQ.oi_liquidacion,
SEC.policy
FROM 
LIQ19_LIQUIDACION as LIQ,
LIQ25_PERSONAL_LIQ as LIQPER,
NMD_SECURITY(class=\'NucleusRH.Base.Liquidacion.Liquidacion.LIQUIDACION\') as SEC
JOIN 
LIQ.oi_liquidacion LEFT OUTER LIQPER.oi_liquidacion,
LIQ.oi_liquidacion LEFT OUTER SEC.id
WHERE 1=1                       
{%?(#SOURCE:@oi_empresa!='')    {% and LIQ.oi_empresa={#SOURCE:@oi_empresa} %} {% %} %}
{%?(#SOURCE:@oi_personal_emp!='')    {% and LIQPER.oi_personal_emp={#SOURCE:@oi_personal_emp} %} {% %} %}

{%?(#SOURCE:@liq_f_liq_des!='')  {% and LIQ.e_periodo>={#SOURCE:@liq_f_liq_des} %} {% %} %}
{%?(#SOURCE:@liq_f_liq_has!='')  {% and LIQ.e_periodo<={#SOURCE:@liq_f_liq_has} %} {% %} %}

{%?(#SOURCE:@liq_f_pag_des!='')  {% and GetPer(LIQ.f_pago)>={#SOURCE:@liq_f_pag_des} %} {% %} %}
{%?(#SOURCE:@liq_f_pag_has!='')  {% and GetPer(LIQ.f_pago)<={#SOURCE:@liq_f_pag_has} %} {% %} %}

')/ROWS/ROW
